  v_expected_function_acl jsonb := '[{"objectIdentity":"public.activate_deployment_clinic(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, timestamp with time zone, integer, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.activate_deployment_hardware_shell(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer, uuid, text, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.activate_deployment_provider_shell(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer, uuid, text, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.activate_deployment_sterilizer_shell(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer, uuid, text, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.activate_deployment_workstation_shell(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer, uuid, text, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.bind_deployment_hardware_target(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer, uuid, text, text, uuid, text, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.claim_deployment_activation_execution_session(text, uuid, text, uuid, text, text, text, timestamp with time zone, timestamp with time zone, integer, text, text, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.complete_deployment_activation_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, timestamp with time zone, integer, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.complete_deployment_hardware_shell_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, text, timestamp with time zone, integer, uuid, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.complete_deployment_provider_shell_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, text, timestamp with time zone, integer, uuid, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.complete_deployment_sterilizer_shell_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, text, timestamp with time zone, integer, uuid, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.complete_deployment_workstation_shell_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, text, timestamp with time zone, integer, uuid, jsonb, jsonb, timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_has_clinic_role(uuid, text[])","grantee":"authenticated","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_has_clinic_role(uuid, text[])","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_is_clinic_member(uuid)","grantee":"authenticated","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_is_clinic_member(uuid)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_is_global_super_admin()","grantee":"authenticated","privilegeType":"EXECUTE"},{"objectIdentity":"public.current_actor_is_global_super_admin()","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.persist_deployment_recovery_plan(uuid, text, uuid, text, text, text, text, text, text, boolean, boolean, jsonb, jsonb, jsonb, integer, integer, jsonb, jsonb, jsonb)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.progress_deployment_activation_execution_dependency(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, timestamp with time zone, timestamp with time zone, integer, uuid, text, text, integer, text, text, text, text, integer, text[], timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.start_deployment_activation_execution_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, timestamp with time zone, integer)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.start_deployment_activation_execution_next_item(uuid, text, uuid, text, text, text, timestamp with time zone, uuid, text, text, integer, text, text, text, integer, text[], timestamp with time zone)","grantee":"service_role","privilegeType":"EXECUTE"},{"objectIdentity":"public.start_deployment_activation_execution_session(uuid, text, uuid, text, text, text, timestamp with time zone, timestamp with time zone, integer)","grantee":"service_role","privilegeType":"EXECUTE"}]'::jsonb;
BEGIN
  IF current_setting('server_version_num')::integer < 150000 THEN
    RAISE EXCEPTION 'PostgreSQL 15 or newer is required';
  END IF;

  IF to_regnamespace('public') IS NULL OR to_regnamespace('auth') IS NULL
     OR to_regnamespace('storage') IS NULL OR to_regnamespace('extensions') IS NULL
     OR to_regclass('auth.users') IS NULL OR to_regprocedure('auth.uid()') IS NULL
     OR to_regprocedure('gen_random_uuid()') IS NULL
     OR to_regprocedure('digest(bytea,text)') IS NULL THEN
    RAISE EXCEPTION 'Required Supabase schemas, auth objects, UUID, or cryptographic prerequisites are missing';
  END IF;

  SELECT count(*) INTO actual_count FROM pg_tables
  WHERE schemaname = 'public' AND tablename IN
    (SELECT jsonb_array_elements_text(v_tables));
  IF actual_count <> jsonb_array_length(v_tables) THEN
    RAISE EXCEPTION 'Application table count/name mismatch: expected %, found %', jsonb_array_length(v_tables), actual_count;
  END IF;

  FOR item IN SELECT value FROM jsonb_array_elements(v_columns) LOOP
    SELECT format_type(a.atttypid, a.atttypmod),
           NOT a.attnotnull,
           pg_get_expr(d.adbin, d.adrelid)
      INTO actual, actual_bool, actual2
      FROM pg_attribute a
      JOIN pg_class c ON c.oid = a.attrelid
      JOIN pg_namespace n ON n.oid = c.relnamespace
      LEFT JOIN pg_attrdef d ON d.adrelid = a.attrelid AND d.adnum = a.attnum
     WHERE n.nspname = 'public' AND c.relname = item->>'table'
       AND a.attname = item->>'name' AND a.attnum > 0 AND NOT a.attisdropped;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Missing column %.%', item->>'table', item->>'name';
    END IF;
    IF regexp_replace(coalesce(actual, ''), '\\s+', ' ', 'g') IS DISTINCT FROM regexp_replace(coalesce(item->>'dataType', ''), '\\s+', ' ', 'g') THEN
      RAISE EXCEPTION 'Column type mismatch %.%: expected %, found %', item->>'table', item->>'name', item->>'dataType', actual;
    END IF;

    IF actual_bool IS DISTINCT FROM (item->>'nullable')::boolean
       OR regexp_replace(coalesce(actual2, ''), '\\s+', ' ', 'g') IS DISTINCT FROM regexp_replace(coalesce(item->>'defaultExpression', ''), '\\s+', ' ', 'g') THEN
      RAISE EXCEPTION 'Column nullability/default mismatch %.%', item->>'table', item->>'name';
    END IF;
  END LOOP;

  FOR item IN SELECT value FROM jsonb_array_elements(v_constraints) LOOP
    SELECT pg_get_constraintdef(con.oid, true), con.contype::text INTO actual, actual2
    FROM pg_constraint con JOIN pg_class c ON c.oid = con.conrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname='public' AND c.relname=item->>'table' AND con.conname=item->>'name';
    IF NOT FOUND OR regexp_replace(coalesce(actual, ''), '\\s+', ' ', 'g') IS DISTINCT FROM regexp_replace(coalesce(item->>'definition', ''), '\\s+', ' ', 'g')
       OR actual2 IS DISTINCT FROM item->>'type' THEN
      RAISE EXCEPTION 'Constraint definition mismatch %.%', item->>'table', item->>'name';
    END IF;
  END LOOP;

  FOR item IN SELECT value FROM jsonb_array_elements(v_indexes) LOOP
    SELECT pg_get_indexdef(i.indexrelid) INTO actual
    FROM pg_index i JOIN pg_class x ON x.oid=i.indexrelid
    JOIN pg_namespace n ON n.oid=x.relnamespace
    WHERE n.nspname='public' AND x.relname=item->>'name' AND NOT EXISTS
      (SELECT 1 FROM pg_constraint con WHERE con.conindid=i.indexrelid);
    IF NOT FOUND OR regexp_replace(coalesce(actual, ''), '\\s+', ' ', 'g') NOT LIKE '%' || regexp_replace(coalesce(item->>'definition', ''), '\\s+', ' ', 'g') THEN
      RAISE EXCEPTION 'Non-constraint index definition mismatch %', item->>'name';
    END IF;
  END LOOP;
  SELECT count(*) INTO actual_count FROM pg_indexes
   WHERE schemaname='public' AND indexname IN
     (SELECT value->>'name' FROM jsonb_array_elements(v_indexes));
  IF actual_count <> 90 THEN RAISE EXCEPTION 'Expected 90 non-constraint indexes, found %', actual_count; END IF;

  FOR item IN SELECT value FROM jsonb_array_elements(v_functions) LOOP
    IF NOT EXISTS (
      SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid=p.pronamespace JOIN pg_language l ON l.oid=p.prolang
      WHERE n.nspname='public' AND p.proname || '(' || pg_get_function_identity_arguments(p.oid) || ')' = item->>'signature'
        AND l.lanname=item->>'language'
        AND CASE p.provolatile WHEN 'i' THEN 'IMMUTABLE' WHEN 's' THEN 'STABLE' ELSE 'VOLATILE' END=item->>'volatility'
        AND CASE WHEN p.prosecdef THEN 'DEFINER' ELSE 'INVOKER' END=item->>'security'
        AND p.proconfig @> ARRAY['search_path=pg_catalog, public']
    ) THEN RAISE EXCEPTION 'Function attributes mismatch %', item->>'signature'; END IF;
  END LOOP;

  IF (SELECT count(*) FROM jsonb_array_elements(v_functions)) <> 28
     OR (SELECT count(*) FROM jsonb_array_elements(v_functions) f WHERE f->>'name' IN (SELECT jsonb_array_elements_text(v_runtime_names))) <> 17
     OR (SELECT count(*) FROM jsonb_array_elements(v_functions) f WHERE f->>'name' IN (SELECT jsonb_array_elements_text(v_trigger_helpers))) <> 8 THEN
    RAISE EXCEPTION 'Function category counts do not match 28 total, 17 runtime RPCs, and 8 trigger helpers';
  END IF;

  FOR item IN SELECT value FROM jsonb_array_elements(v_triggers) LOOP
    SELECT pg_get_triggerdef(t.oid, true) INTO actual
    FROM pg_trigger t JOIN pg_class c ON c.oid=t.tgrelid JOIN pg_namespace n ON n.oid=c.relnamespace
    JOIN pg_proc p ON p.oid=t.tgfoid
    WHERE n.nspname='public' AND c.relname=item->>'table' AND t.tgname=item->>'name'
      AND p.proname=item->>'function' AND NOT t.tgisinternal;
    IF NOT FOUND THEN RAISE EXCEPTION 'Trigger attachment mismatch %.%', item->>'table', item->>'name'; END IF;
  END LOOP;

  SELECT count(*) INTO actual_count FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace
   WHERE n.nspname='public' AND c.relname IN (SELECT jsonb_array_elements_text(v_rls_tables)) AND c.relrowsecurity;
  IF actual_count <> 23 THEN RAISE EXCEPTION 'Expected RLS on 23 exact tables, found %', actual_count; END IF;

  FOR item IN SELECT value FROM jsonb_array_elements(v_policies) LOOP
    IF NOT EXISTS (
      SELECT 1 FROM pg_policies
      WHERE schemaname='public' AND tablename=item->>'table' AND policyname=item->>'name'
        AND cmd=item->>'command'
        AND to_jsonb(roles)=item->'roles'
        AND regexp_replace(coalesce(qual, ''), '\\s+', ' ', 'g') IS NOT DISTINCT FROM regexp_replace(coalesce(item->>'using', ''), '\\s+', ' ', 'g')
        AND regexp_replace(coalesce(with_check, ''), '\\s+', ' ', 'g') IS NOT DISTINCT FROM regexp_replace(coalesce(item->>'withCheck', ''), '\\s+', ' ', 'g')
    ) THEN RAISE EXCEPTION 'Policy definition mismatch %.%', item->>'table', item->>'name'; END IF;
  END LOOP;
  IF (SELECT count(*) FROM pg_policies WHERE schemaname='public'
      AND tablename IN (SELECT jsonb_array_elements_text(v_tables))) <> 33 THEN
    RAISE EXCEPTION 'Expected exactly 33 application policies';
  END IF;

  IF EXISTS (
    SELECT 1 FROM information_schema.role_table_grants
    WHERE table_schema='public' AND table_name IN (SELECT jsonb_array_elements_text(v_tables))
      AND grantee IN ('PUBLIC','anon')
  ) THEN RAISE EXCEPTION 'Anonymous/PUBLIC application table privilege detected'; END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.role_table_grants
    WHERE table_schema='public' AND grantee='authenticated'
      AND table_name IN (SELECT jsonb_array_elements_text(v_tables))
      AND ((privilege_type='SELECT' AND table_name NOT IN (SELECT jsonb_array_elements_text(v_auth_select)))
        OR (privilege_type IN ('INSERT','UPDATE') AND table_name NOT IN (SELECT jsonb_array_elements_text(v_auth_write)))
        OR privilege_type IN ('DELETE','TRUNCATE','REFERENCES','TRIGGER'))
  ) THEN RAISE EXCEPTION 'Unexpected authenticated direct table privilege detected'; END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.routine_privileges
    WHERE specific_schema='public' AND grantee IN ('PUBLIC','anon')
      AND routine_name IN (SELECT value->>'name' FROM jsonb_array_elements(v_functions))
  ) THEN RAISE EXCEPTION 'Unexpected PUBLIC/anon function execution detected'; END IF;
  IF EXISTS (
    SELECT 1 FROM information_schema.routine_privileges
    WHERE specific_schema='public' AND grantee='authenticated'
      AND routine_name IN (SELECT jsonb_array_elements_text(v_runtime_names || v_trigger_helpers))
  ) THEN RAISE EXCEPTION 'Runtime RPC or trigger helper exposed to authenticated'; END IF;

  IF to_regclass('public.platform_operator_roles') IS NULL
     OR to_regclass('public.clinic_memberships') IS NULL
     OR to_regclass('public.patient_external_identifiers') IS NULL THEN
    RAISE EXCEPTION 'Membership, global operator, or external patient identity structure is missing';
  END IF;
  IF EXISTS (
    SELECT 1 FROM unnest(ARRAY['patients','cycles','load_items','packs','patient_traces','audit_logs']::text[]) t(name)
    WHERE NOT EXISTS (SELECT 1 FROM information_schema.columns c
      WHERE c.table_schema='public' AND c.table_name=t.name AND c.column_name='clinic_id')
  ) THEN RAISE EXCEPTION 'Required clinic ownership column is missing'; END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname='public'
       AND indexname='clinical_workstations_display_order_name_idx'
       AND indexdef LIKE '%(display_order, name)%' AND indexdef NOT LIKE 'CREATE UNIQUE%')
     OR NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname='public'
       AND indexname='providers_clinic_normalized_name_uidx')
     OR NOT EXISTS (SELECT 1 FROM pg_indexes WHERE schemaname='public'
       AND indexname='sterilizers_clinic_normalized_name_uidx') THEN
    RAISE EXCEPTION 'Approved workstation/provider/sterilizer index posture is missing';
  END IF;

  -- Exact authoritative object sets: reject both missing and unexpected objects.
  IF (
    SELECT coalesce(jsonb_agg(tablename ORDER BY tablename), '[]'::jsonb)
    FROM pg_tables WHERE schemaname = 'public'
  ) IS DISTINCT FROM v_tables THEN
    RAISE EXCEPTION 'Exact application table set mismatch';
  END IF;

  IF (
    SELECT coalesce(jsonb_agg(jsonb_build_object('table', c.relname, 'name', con.conname)
             ORDER BY c.relname, con.conname), '[]'::jsonb)
    FROM pg_constraint con
    JOIN pg_class c ON c.oid = con.conrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname IN
      (SELECT jsonb_array_elements_text(v_tables))
  ) IS DISTINCT FROM (
    SELECT jsonb_agg(jsonb_build_object('table', value->>'table', 'name', value->>'name')
             ORDER BY value->>'table', value->>'name')
    FROM jsonb_array_elements(v_constraints)
  ) THEN
    RAISE EXCEPTION 'Exact application constraint set mismatch';
  END IF;

  IF (
    SELECT coalesce(jsonb_agg(x.relname ORDER BY x.relname), '[]'::jsonb)
    FROM pg_index i JOIN pg_class x ON x.oid = i.indexrelid
    JOIN pg_class t ON t.oid = i.indrelid
    JOIN pg_namespace n ON n.oid = t.relnamespace
    WHERE n.nspname = 'public' AND t.relname IN
      (SELECT jsonb_array_elements_text(v_tables))
      AND NOT EXISTS (SELECT 1 FROM pg_constraint con WHERE con.conindid = i.indexrelid)
  ) IS DISTINCT FROM (
    SELECT jsonb_agg(value->>'name' ORDER BY value->>'name')
    FROM jsonb_array_elements(v_indexes)
  ) THEN
    RAISE EXCEPTION 'Exact non-constraint index set mismatch';
  END IF;

  IF (
    SELECT coalesce(jsonb_agg(p.proname || '(' || pg_get_function_identity_arguments(p.oid) || ')'
             ORDER BY p.proname, pg_get_function_identity_arguments(p.oid)), '[]'::jsonb)
    FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = 'public'
  ) IS DISTINCT FROM (
    SELECT jsonb_agg(value->>'signature' ORDER BY value->>'signature')
    FROM jsonb_array_elements(v_functions)
  ) THEN
    RAISE EXCEPTION 'Exact application function signature set mismatch';
  END IF;

  IF (
    SELECT coalesce(jsonb_agg(c.relname || '.' || t.tgname ORDER BY c.relname, t.tgname), '[]'::jsonb)
    FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND NOT t.tgisinternal
  ) IS DISTINCT FROM (
    SELECT jsonb_agg((value->>'table') || '.' || (value->>'name')
             ORDER BY value->>'table', value->>'name')
    FROM jsonb_array_elements(v_triggers)
  ) THEN
    RAISE EXCEPTION 'Exact application trigger set mismatch';
  END IF;

  IF (
    SELECT coalesce(jsonb_agg(c.relname ORDER BY c.relname), '[]'::jsonb)
    FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relkind IN ('r', 'p') AND c.relrowsecurity
  ) IS DISTINCT FROM v_rls_tables THEN
    RAISE EXCEPTION 'Exact RLS-enabled application table set mismatch';
  END IF;

  -- Exact direct table ACL tuples for every non-owner grantee.
  IF EXISTS (
    WITH expected AS (
      SELECT value->>'objectIdentity' object_identity,
             value->>'grantee' grantee,
             value->>'privilegeType' privilege_type
      FROM jsonb_array_elements(v_expected_table_acl)
    ), actual AS (
      SELECT 'public.' || c.relname object_identity,
             CASE WHEN acl.grantee = 0 THEN 'PUBLIC' ELSE grantee.rolname END grantee,
             acl.privilege_type
      FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
      CROSS JOIN LATERAL aclexplode(coalesce(c.relacl, acldefault('r', c.relowner))) acl
      LEFT JOIN pg_roles grantee ON grantee.oid = acl.grantee
      WHERE n.nspname = 'public' AND c.relname IN
        (SELECT jsonb_array_elements_text(v_tables))
        AND acl.grantee <> c.relowner
    )
    SELECT object_identity, grantee, privilege_type FROM expected
    EXCEPT
    SELECT object_identity, grantee, privilege_type FROM actual
  ) THEN
    RAISE EXCEPTION 'Missing required direct application-table ACL tuple';
  END IF;
  IF EXISTS (
    WITH expected AS (
      SELECT value->>'objectIdentity' object_identity,
             value->>'grantee' grantee,
             value->>'privilegeType' privilege_type
      FROM jsonb_array_elements(v_expected_table_acl)
    ), actual AS (
      SELECT 'public.' || c.relname object_identity,
             CASE WHEN acl.grantee = 0 THEN 'PUBLIC' ELSE grantee.rolname END grantee,
             acl.privilege_type
      FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
      CROSS JOIN LATERAL aclexplode(coalesce(c.relacl, acldefault('r', c.relowner))) acl
      LEFT JOIN pg_roles grantee ON grantee.oid = acl.grantee
      WHERE n.nspname = 'public' AND c.relname IN
        (SELECT jsonb_array_elements_text(v_tables))
        AND acl.grantee <> c.relowner
    )
    SELECT object_identity, grantee, privilege_type FROM actual
    EXCEPT
    SELECT object_identity, grantee, privilege_type FROM expected
  ) THEN
    RAISE EXCEPTION 'Unexpected direct application-table ACL tuple, grantee, object, or privilege';
  END IF;

  -- Exact direct function EXECUTE tuples by canonical identity signature.
  IF EXISTS (
    WITH expected AS (
      SELECT value->>'objectIdentity' object_identity,
             value->>'grantee' grantee,
             value->>'privilegeType' privilege_type
      FROM jsonb_array_elements(v_expected_function_acl)
    ), actual AS (
      SELECT 'public.' || p.proname || '(' || pg_get_function_identity_arguments(p.oid) || ')' object_identity,
             CASE WHEN acl.grantee = 0 THEN 'PUBLIC' ELSE grantee.rolname END grantee,
             acl.privilege_type
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      CROSS JOIN LATERAL aclexplode(coalesce(p.proacl, acldefault('f', p.proowner))) acl
      LEFT JOIN pg_roles grantee ON grantee.oid = acl.grantee
      WHERE n.nspname = 'public' AND acl.grantee <> p.proowner
    )
    SELECT object_identity, grantee, privilege_type FROM expected
    EXCEPT
    SELECT object_identity, grantee, privilege_type FROM actual
  ) THEN
    RAISE EXCEPTION 'Missing required function EXECUTE ACL tuple or wrong signature';
  END IF;
  IF EXISTS (
    WITH expected AS (
      SELECT value->>'objectIdentity' object_identity,
             value->>'grantee' grantee,
             value->>'privilegeType' privilege_type
      FROM jsonb_array_elements(v_expected_function_acl)
    ), actual AS (
      SELECT 'public.' || p.proname || '(' || pg_get_function_identity_arguments(p.oid) || ')' object_identity,
             CASE WHEN acl.grantee = 0 THEN 'PUBLIC' ELSE grantee.rolname END grantee,
             acl.privilege_type
      FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      CROSS JOIN LATERAL aclexplode(coalesce(p.proacl, acldefault('f', p.proowner))) acl
      LEFT JOIN pg_roles grantee ON grantee.oid = acl.grantee
      WHERE n.nspname = 'public' AND acl.grantee <> p.proowner
    )
    SELECT object_identity, grantee, privilege_type FROM actual
    EXCEPT
    SELECT object_identity, grantee, privilege_type FROM expected
  ) THEN
    RAISE EXCEPTION 'Unexpected function ACL tuple, grantee, signature, or privilege';
  END IF;
END
$baseline_validation$;